package com.example.loggingapi.service;

import com.example.loggingapi.model.CreateItemRequest;
import com.example.loggingapi.model.ItemResponse;
import com.example.loggingapi.repo.ItemRepository;
import com.example.loggingapi.repo.StoredItem;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;

import java.util.List;
import java.util.Optional;
import java.util.UUID;

@Service
public class ItemService {

    private static final Logger log = LoggerFactory.getLogger(ItemService.class);

    private final ItemRepository repository;

    public ItemService(ItemRepository repository) {
        this.repository = repository;
    }

    public List<ItemResponse> list() {
        log.debug("Service list items");
        List<ItemResponse> items = repository.findAll().stream()
                .map(s -> new ItemResponse(s.getId(), s.getName()))
                .toList();
        return items;
    }

    public Optional<ItemResponse> get(String id) {
        log.debug("Service get item, id={}", id);
        return repository.findById(id).map(s -> new ItemResponse(s.getId(), s.getName()));
    }

    public ItemResponse create(CreateItemRequest body) {
        String name = body != null ? body.getName() : null;
        if (!StringUtils.hasText(name)) {
            log.info("Create item rejected: name is required");
            throw new IllegalArgumentException("name is required");
        }

        String id = UUID.randomUUID().toString();
        StoredItem stored = new StoredItem(id, name.trim());
        repository.save(stored);
        log.info("Item created, id={}", id);
        return new ItemResponse(stored.getId(), stored.getName());
    }

    public boolean delete(String id) {
        log.debug("Service delete item, id={}", id);
        boolean deleted = repository.deleteById(id);
        if (deleted) {
            log.info("Item deleted, id={}", id);
        }
        return deleted;
    }
}

