package com.example.loggingapi.repo;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Repository;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Repository
public class ItemRepository {

    private static final Logger log = LoggerFactory.getLogger(ItemRepository.class);

    private final ConcurrentHashMap<String, StoredItem> store = new ConcurrentHashMap<>();

    public List<StoredItem> findAll() {
        log.debug("Repository findAll");
        return new ArrayList<>(store.values());
    }

    public Optional<StoredItem> findById(String id) {
        log.debug("Repository findById, id={}", id);
        return Optional.ofNullable(store.get(id));
    }

    public void save(StoredItem item) {
        log.debug("Repository save, id={}", item.getId());
        store.put(item.getId(), item);
    }

    public boolean deleteById(String id) {
        log.debug("Repository deleteById, id={}", id);
        return store.remove(id) != null;
    }
}

